import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as c}from"./nyalra_no_mono-8344e451.js";import{_ as p,W as s,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const f={},u=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/b70ccd01859b854f00e0f0d2fcfcb32f.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>事情多多，今夜我心情低落得相当沮丧。</p><p>然而，我不能说出原因。明明不说明原因，却流露出沮丧的样子。这种模式对于接收者来说是最烦人的了吧。对不起。</p><p>浏览Twitter时，只有「沮丧」的信息传来。于是，不可避免地很在意。并不是担心，而是完全的好奇心。这个人究竟经历了什么导致他陷入悲伤之中呢？一但看到，就会想要去探究原因，这是人性所驱使。然而，无论是追溯到他的账号还是相关的人，都没有写下任何理由。真气人……。不，其实是自作多情的错，但是既然「信息」已经流出，就不可避免地想要挖掘其意义。这是无法改变的。如果在互联网上倾泻悲伤，就一定要写上原因！接收者想要得到满意的答案。只是如此渴望知道这个人为何哭泣，虽然就算知道也无意帮忙。但是，你一定也想知道吧……！一定会感到好奇而心烦吧……！</p><p>然而，悲伤的原因大部分是因为人际关系或自作自受，如果写出来会变得更加麻烦，所以只能自己消化。今晚，我沮丧的原因完全是我自找的，简单来说是因为我过于懒散而错过了一个活动。在这种时候，人类会因为自己的脆弱而一时把责任推给他人，试图减轻伤害。「都怪那个家伙没有提醒！」「都怪这家伙给我安排了工作忙得不可开交！」等等。这是借口。啊，意识到自己在脑海里乱发脾气，并因此自责而进一步沮丧。现在就是这种状态。</p><p>这是悲伤的连锁反应。虽然悲伤，但是不能说出悲伤的原因。为了不让他人感到不快，无法表明自己沮丧的事实。需要自己解决并接受一切，这将成为压力，进一步加剧痛苦。从而逐渐陷入循环，悲伤回到起点。无限地积累压力。</p><p>这种「真正悲伤的事情却无法向他人倾诉」真是麻烦。不，准确来说，也许是可以说出来，但说了也没有意义，只会降低别人对自己的评价……这种状态非常难以化为笑谈。那种痛苦让人无法忍受。这才是真正的困扰。即使说出来，也只会变成「这家伙在撒娇」之类的程度，是非常无聊的烦恼。</p><p>然而，这次或许是唯一的成功例子。因为仅仅通过将当前的心情记录下来，就已经填满了一次连载的篇幅。当然，沮丧的原因远不止一篇稿费，甚至可以说是损失了数倍的稿费。你一定很好奇吧。但是我不说。因为这完全是我自己的错误，没有给别人添麻烦就是我唯一的安慰。（并不是装乖，只是单纯地因为给别人添麻烦的错误会带来更大的麻烦）</p><p>像这样，怀抱着无法向他人诉说的烦恼而继续生活，这就是成为成年人的意思吗？大家都怀抱着各种烦恼和悲伤吗？还是说，应该试着和恋人、朋友倾诉一下呢？这是我自闭症的部分症状吗？年幼的我还无法判断……。因为没有写下原因，读者和周围的人，没有人能够安慰我。唯一能治愈受伤心灵的，只有一次稿费而已。</p><hr><p><img src="'+c+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/37a5f4442a6ddd32ec4b202f31d8cea0.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【巨大的小樱手办】超级巨大的小樱手办。因为这个尺寸，现在的价格也非常昂贵，但当时由于过于庞大，库存积压导致可以以半价购买。如今，它已经成为稀有物品，价格大幅上涨，超过最初的销售价格。想要手办的瞬间，就买下来吧。就算存款有点危险，也绝对没问题的！</p></blockquote>',12);function g(x,y){const n=a("ExternalLinkIcon"),r=a("RouterLink");return s(),_("div",null,[i(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第17回／一人で悲しみを抱えながら落ちていく"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_16.html"},{default:m(()=>[t("【奈亚拉面壁自语】第16回｜最终「善」将获胜【230307】")]),_:1})])]),b])}const C=p(f,[["render",g],["__file","nyalra_kb_17.html.vue"]]);export{C as default};
